import{_ as t,o as r,c as n,a2 as e}from"./chunks/framework.DIMps2S2.js";const f=JSON.parse('{"title":"完成首笔基金定投","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"funds-and-wealth/funds/first-fund-regular-investment.md","filePath":"zh-CN/funds-and-wealth/funds/first-fund-regular-investment.md"}'),l={name:"funds-and-wealth/funds/first-fund-regular-investment.md"};function o(s,a,i,p,d,u){return r(),n("div",null,[...a[0]||(a[0]=[e('<h1 id="完成首笔基金定投" tabindex="-1">完成首笔基金定投 <a class="header-anchor" href="#完成首笔基金定投" aria-label="Permalink to &quot;完成首笔基金定投&quot;">​</a></h1><p>在本教程结束时，你将设置好一个自动基金定投计划，并在基金订单页面看到它已排定下次执行时间。</p><p>完成这个教程大约需要 <strong>5 分钟</strong>，随时都可以操作，无需等待特定交易时段。</p><h2 id="开始前的准备" tabindex="-1">开始前的准备 <a class="header-anchor" href="#开始前的准备" aria-label="Permalink to &quot;开始前的准备&quot;">​</a></h2><p>确认以下两项：</p><ul><li>账户中有港元或新加坡元余额（至少等于一期定投金额）</li><li>已了解基金的基本概念（风险等级、申赎规则）</li></ul><p>如果还不熟悉基金类型，可先阅读<a href="/wiki/funds-and-wealth/funds/fund-basics">基金</a>了解基础知识。</p><blockquote><p>基金定投不保证盈利，过往收益不代表未来表现。请根据自身风险承受能力设置定投金额，不要投入不能承担亏损的资金。</p></blockquote><h2 id="第一步-进入基金定投入口" tabindex="-1">第一步：进入基金定投入口 <a class="header-anchor" href="#第一步-进入基金定投入口" aria-label="Permalink to &quot;第一步：进入基金定投入口&quot;">​</a></h2><p>打开长桥 App，点击底部导航的**「市场」<strong>，选择</strong>「财富」**。</p><p>在财富页面找到**「基金定投」**入口并点击。</p><p>你会看到可以定投的基金列表，包含名称、最新净值、近期收益等信息。</p><h2 id="第二步-选择基金" tabindex="-1">第二步：选择基金 <a class="header-anchor" href="#第二步-选择基金" aria-label="Permalink to &quot;第二步：选择基金&quot;">​</a></h2><p>本教程使用**「华夏精选美元货币基金 Class B USD」**作为示例——它是货币型基金，风险较低，适合入门体验定投流程。</p><p>在搜索栏输入基金名称，或直接从列表中找到它。点击进入该基金的详情页，查看：</p><ul><li><strong>风险等级</strong>：低（货币型）</li><li><strong>计价货币</strong>：USD（如账户没有美元，可选一只 HKD 计价的货币基金）</li></ul><p>点击**「定投」**按钮。</p><blockquote><p>选哪只基金对操作流程没有影响，任何上架基金均可定投。第一次可以选低风险货币基金体验流程，之后再根据自己的目标选择其他类型。</p></blockquote><h2 id="第三步-设置定投参数" tabindex="-1">第三步：设置定投参数 <a class="header-anchor" href="#第三步-设置定投参数" aria-label="Permalink to &quot;第三步：设置定投参数&quot;">​</a></h2><p>在定投设置页面填写以下参数：</p><p><strong>定投金额</strong>：输入 <strong>500</strong>（港元或美元，与基金计价币种一致）。这是每期自动扣款并买入的固定金额。</p><p><strong>定投周期</strong>：选择**「每月」**。</p><p><strong>定投日</strong>：选择 <strong>15 日</strong>（即每月 15 日自动执行一次）。若 15 日是非交易日，系统自动顺延至下一个交易日。</p><p>你会看到页面底部显示**「下次执行时间」**——这是你的定投计划第一次自动执行的日期。</p><h2 id="第四步-确认并提交" tabindex="-1">第四步：确认并提交 <a class="header-anchor" href="#第四步-确认并提交" aria-label="Permalink to &quot;第四步：确认并提交&quot;">​</a></h2><p>检查以下内容：</p><ul><li>基金名称正确</li><li>金额：500（与计价币种一致）</li><li>周期：每月 15 日</li><li>下次执行时间已显示</li></ul><p>点击**「确认定投」**，再次确认风险提示后提交。</p><p>你会看到提示「定投计划已设置成功」。</p><h2 id="第五步-查看定投计划" tabindex="-1">第五步：查看定投计划 <a class="header-anchor" href="#第五步-查看定投计划" aria-label="Permalink to &quot;第五步：查看定投计划&quot;">​</a></h2><p>回到主页，进入**「市场 → 财富 → 基金订单」<strong>，切换到</strong>「基金定投」**标签。</p><p>你会看到刚才设置的定投计划，显示：</p><ul><li>状态：<strong>执行中</strong></li><li>定投金额：500</li><li>下次执行时间：下一个 15 日（或顺延后的交易日）</li></ul><p><strong>恭喜！你的基金定投计划已经生效。</strong></p><p>从下次执行日起，系统每月自动从账户余额扣款并买入基金，无需你手动操作。T+3 日份额到账，T+4 日起可以看到收益变化。</p><h2 id="管理定投计划" tabindex="-1">管理定投计划 <a class="header-anchor" href="#管理定投计划" aria-label="Permalink to &quot;管理定投计划&quot;">​</a></h2><p>定投运行后，你可以随时：</p><ul><li><strong>暂停</strong>：临时停止自动扣款，已持有份额不受影响</li><li><strong>恢复</strong>：重新启用暂停的计划</li><li><strong>终止</strong>：永久取消计划，已买入的份额继续持有，可随时赎回</li></ul><p>操作入口：<strong>基金订单 → 基金定投 → 选择对应计划</strong>。</p><hr><ul><li>查看申赎规则与截止时间：<a href="/wiki/funds-and-wealth/funds/fund-trading-rules">基金交易规则</a></li><li>了解基金手续费：<a href="/wiki/funds-and-wealth/funds/fund-fees">基金收费</a></li></ul>',41)])])}const g=t(l,[["render",o]]);export{f as __pageData,g as default};
